    73		privateKeyBlock, _ := pem.Decode([]byte(e.PrivateKey))
    74		if privateKeyBlock == nil {
    75			return errors.New("failed to parse private key PEM")
    76		}
    77	
    78		err = validateKeyLength(privateKeyBlock)
    79		if err != nil {
