    84		if certificateBlock == nil {
    85			return errors.New("failed to parse certificate PEM")
    86		}
    87	
    88		// make sure we have a valid x509 certificate
    89		_, err = x509.ParseCertificate(certificateBlock.Bytes)
    90		if err != nil {
    91			return fmt.Errorf("failed to parse certificate: %w", err)
    92		}
    93	
    94		// validate that the cert was generated with the given private key
    95		_, err = tls.X509KeyPair([]byte(e.Certificate), []byte(e.PrivateKey))
    96		if err != nil {
    97			return err
    98		}
