   115	func validateKeyLength(privateKeyBlock *pem.Block) error {
   116		if privateKeyBlock.Type != "RSA PRIVATE KEY" {
   117			return nil
   118		}
   119	
   120		key, err := x509.ParsePKCS1PrivateKey(privateKeyBlock.Bytes)
   121		if err != nil {
   122			return err
   123		}
   124	
   125		keyBitLen := key.N.BitLen()
   126	
   127		if version.IsFIPS() {
   128			return fipsLenCheck(keyBitLen)
   129		}
   130	
   131		return nonFipsLenCheck(keyBitLen)
   132	}
   133	
   134	func nonFipsLenCheck(keyLen int) error {
   135		// ensure private key is of the correct length
   136		if keyLen < MinKeyLength {
   137			return errors.New("key length must be at least 2048 bits")
   138		}
   139	
   140		return nil
   141	}
   142	
   143	func fipsLenCheck(keyLen int) error {
   144		if keyLen != 2048 && keyLen != 3072 && keyLen != 4096 {
   145			return errors.New("key length invalid: only RSA lengths of 2048, 3072, and 4096 are allowed in FIPS mode")
   146		}
   147		return nil
   148	}
