   272	// helper struct to persist upstream parent information when ready upstream list is built out
   273	type readyListener struct {
   274		listenerKey      proxycfg.APIGatewayListenerKey
   275		listenerCfg      structs.APIGatewayListener
   276		boundListenerCfg structs.BoundAPIGatewayListener
   277		routeReferences  map[structs.ResourceReference]struct{}
   278		upstreams        []structs.Upstream
