   372	func resolveAPIListenerTLSConfig(listenerTLSCfg structs.APIGatewayTLSConfiguration) (*structs.GatewayTLSConfig, error) {
   373		var mergedCfg structs.GatewayTLSConfig
   374	
   375		if !listenerTLSCfg.IsEmpty() {
   376			if listenerTLSCfg.MinVersion != types.TLSVersionUnspecified {
   377				mergedCfg.TLSMinVersion = listenerTLSCfg.MinVersion
   378			}
   379			if listenerTLSCfg.MaxVersion != types.TLSVersionUnspecified {
   380				mergedCfg.TLSMaxVersion = listenerTLSCfg.MaxVersion
   381			}
   382			if len(listenerTLSCfg.CipherSuites) != 0 {
   383				mergedCfg.CipherSuites = listenerTLSCfg.CipherSuites
   384			}
   385		}
   386	
   387		if err := validateListenerTLSConfig(mergedCfg.TLSMinVersion, mergedCfg.CipherSuites); err != nil {
   388			return nil, err
   389		}
   390	
   391		return &mergedCfg, nil
   392	}
