package api

// FileSystemCertificateConfigEntry manages the configuration for a TLS certificate
// stored on the local filesystem, referenced by file paths.
type FileSystemCertificateConfigEntry struct {
	// Kind of the config entry. This should be set to api.FileSystemCertificate.
	Kind string

	// Name is used to match the config entry with its associated file-system certificate.
	Name string

	// Certificate is the path to the public certificate file on the local filesystem.
	Certificate string

	// PrivateKey is the path to the private key file on the local filesystem.
	PrivateKey string `alias:"private_key"`

	Meta map[string]string `json:",omitempty"`

	// CreateIndex is the Raft index this entry was created at. This is a
	// read-only field.
	CreateIndex uint64

	// ModifyIndex is used for the Check-And-Set operations and can also be fed
	// back into the WaitIndex of the QueryOptions in order to perform blocking
