package xds

import (
	"testing"

	envoy_core_v3 "github.com/envoyproxy/go-control-plane/envoy/config/core/v3"
	envoy_tls_v3 "github.com/envoyproxy/go-control-plane/envoy/extensions/transport_sockets/tls/v3"
	"github.com/stretchr/testify/require"

	"github.com/hashicorp/consul/agent/proxycfg"
	"github.com/hashicorp/consul/agent/structs"
	"github.com/hashicorp/consul/sdk/testutil"
)

func TestSecretsFromSnapshotAPIGateway(t *testing.T) {
	tests := []struct {
		name           string
		fileSystemCerts []structs.FileSystemCertificateConfigEntry
		expectSecrets  []string
	}{
		{
			name:           "no file-system-certificates",
			fileSystemCerts: nil,
			expectSecrets:  nil,
		},
		{
			name: "single file-system-certificate",
			fileSystemCerts: []structs.FileSystemCertificateConfigEntry{
				{
					Kind:        structs.FileSystemCertificate,
					Name:        "test-cert",
					Certificate: "/path/to/cert.pem",
					PrivateKey:  "/path/to/key.pem",
				},
			},
			expectSecrets: []string{"test-cert"},
		},
		{
			name: "multiple file-system-certificates",
			fileSystemCerts: []structs.FileSystemCertificateConfigEntry{
				{
					Kind:        structs.FileSystemCertificate,
					Name:        "cert-one",
					Certificate: "/opt/consul/tls/cert1.crt",
					PrivateKey:  "/opt/consul/tls/cert1.key",
				},
				{
					Kind:        structs.FileSystemCertificate,
					Name:        "cert-two",
					Certificate: "/opt/consul/tls/cert2.crt",
					PrivateKey:  "/opt/consul/tls/cert2.key",
				},
			},
			expectSecrets: []string{"cert-one", "cert-two"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Create a minimal API gateway snapshot
			snap := &proxycfg.ConfigSnapshot{
				Kind: structs.ServiceKindAPIGateway,
			}

			// Add file-system-certificates to the snapshot
			for _, cert := range tt.fileSystemCerts {
				cert := cert
				ref := structs.ResourceReference{
					Kind: structs.FileSystemCertificate,
					Name: cert.Name,
				}
				snap.APIGateway.FileSystemCertificates.Set(ref, &cert)
			}

			// Generate secrets
			g := NewResourceGenerator(testutil.Logger(t), nil, false)
			secrets, err := g.secretsFromSnapshot(snap)
			require.NoError(t, err)

			if tt.expectSecrets == nil {
				require.Empty(t, secrets)
				return
			}

			require.Len(t, secrets, len(tt.expectSecrets))

			// Verify the generated secrets
			secretNames := make(map[string]bool)
			for _, secret := range secrets {
				s, ok := secret.(*envoy_tls_v3.Secret)
				require.True(t, ok, "expected *envoy_tls_v3.Secret, got %T", secret)
				secretNames[s.Name] = true

				// Verify it's using filename data source
				tlsCert := s.GetTlsCertificate()
				require.NotNil(t, tlsCert)

				certChain := tlsCert.GetCertificateChain()
				require.NotNil(t, certChain)
				_, ok = certChain.Specifier.(*envoy_core_v3.DataSource_Filename)
				require.True(t, ok, "certificate chain should use filename data source")

				privateKey := tlsCert.GetPrivateKey()
				require.NotNil(t, privateKey)
				_, ok = privateKey.Specifier.(*envoy_core_v3.DataSource_Filename)
				require.True(t, ok, "private key should use filename data source")
			}

			// Verify all expected secrets are present
			for _, name := range tt.expectSecrets {
				require.True(t, secretNames[name], "expected secret %s not found", name)
			}
		})
	}
}

